	id: string,
	service: ContainerService
): Promise<Response> {
	const existing = await service.get(id);
	if (!existing) {
		return errorResponse(`Container '${id}' not found`, 404);
	}

	await service.destroy(id);
	return new Response(null, { status: 204 });
}

